/// <summary>
/// The <c>KJP_SM_InventCompensationStmtContract</c> class is the data contract for the <c>KJP_SM_InventCompensationStmtReport</c> SSRS report.
/// </summary>
[DataContractAttribute]
public class KJP_SM_InventCompensationStmtContract
{
    List inventCompensationStmtRecIdList = new List(Types::Int64);

}

Method.Source:
/// <summary>
/// Gets or sets the value of the datacontract parameter inventCompensationStmtRecIdList.
/// </summary>
/// <param name = "_inventCompensationStmtRecIdList">
/// Record Ids of the selected inventory compensation statement records.
/// </param>
/// <returns>
/// List containing record Ids of the selected inventory compensation statement records.
/// </returns>
[
    DataMemberAttribute('InventCompensationStmtRecIdList'),
    AifCollectionTypeAttribute('_inventCompensationStmtRecIdList', Types::Int64, extendedTypeStr(RecId)),
    SysOperationControlVisibilityAttribute(False)
]
public List parmInventCompensationStmtRecIdList(List _inventCompensationStmtRecIdList = inventCompensationStmtRecIdList)
{
    inventCompensationStmtRecIdList = _inventCompensationStmtRecIdList;
    return inventCompensationStmtRecIdList;
}
